const repairMojibakeText = (value) => {
  if (typeof value !== 'string') return value;
  let next = value;
  for (let pass = 0; pass < 3; pass++) {
    const before = next;
    TEXT_ENCODING_REPAIRS.forEach(([bad, good]) => { next = next.split(bad).join(good); });
    if (next === before) break;
  }
  return next;
};

const repairStoredText = (value) => {
  if (typeof value === 'string') return repairMojibakeText(value);
  if (Array.isArray(value)) return value.map(repairStoredText);
  if (value && typeof value === 'object') {
    return Object.fromEntries(Object.entries(value).map(([key, item]) => [key, repairStoredText(item)]));
  }
  return value;
};

const normalizeHabitRecords = (records = []) => {
  const recordsByDay = new Map();
  (Array.isArray(records) ? records : []).forEach(record => {
    if (!record?.habitId || !record?.date) return;
    const date = String(record.date).slice(0, 10);
    const key = `${record.habitId}:${date}`;
    const previous = recordsByDay.get(key);
    recordsByDay.set(key, {
      ...(previous || {}),
      ...record,
      habitId: record.habitId,
      date,
      completed: !!record.completed,
      note: record.note || previous?.note || '',
      mood: record.mood ?? previous?.mood ?? 0
    });
  });
  return Array.from(recordsByDay.values());
};

const normalizeLoadedData = (parsed) => {
  parsed = repairStoredText(parsed);
  if (!parsed || !parsed.user || !parsed.habits || !parsed.records) return null;
  parsed.records = normalizeHabitRecords(parsed.records);
  if (!parsed.user.xp) parsed.user.xp = 0;
  if (!parsed.user.level) parsed.user.level = 1;
  if (!parsed.user.levelUpShown) parsed.user.levelUpShown = 1;
  if (parsed.user.notificationsEnabled === undefined) parsed.user.notificationsEnabled = true;
  const normalizedThemeMode = parsed.user.themeMode === 'pinkLight' ? 'pinkLight' : 'pureDark';
  parsed.user.themeMode = normalizedThemeMode;
  parsed.user.accentColor = THEME_ACCENTS[normalizedThemeMode].id;
  parsed.user.iconColor = THEME_ICON_COLORS[normalizedThemeMode].id;
  parsed.user.visualVersion = 'twoThemes2026';
  if (!parsed.dailyNotes) parsed.dailyNotes = {};
  if (!parsed.challenges) parsed.challenges = [];
  if (!parsed.customHabitCategories) parsed.customHabitCategories = [];
  if (!parsed.agendaTaskCategories) parsed.agendaTaskCategories = [];
  if (!parsed.xpAwards) {
    parsed.xpAwards = Object.fromEntries(
      parsed.records.filter(record => record.completed).map(record => [`habit:${record.habitId}:${record.date}`, 0])
    );
  }
  parsed.records.filter(record => record.completed).forEach(record => {
    const awardKey = `habit:${record.habitId}:${record.date}`;
    if (!Object.prototype.hasOwnProperty.call(parsed.xpAwards, awardKey)) {
      parsed.xpAwards[awardKey] = 0;
    }
  });
  parsed.habits.forEach(h => {
    if (!h.lastFocusSession) h.lastFocusSession = null;
    h.icon = normalizeHabitIconId(h.icon, h.category, h.name);
    h.color = normalizeHabitMarkColor(h.color, h.category, parsed.customHabitCategories);
    if (h.frequency === 'Personalizado' || h.frequencyDays) {
      h.frequencyDays = normalizeHabitFrequencyDays(h.frequencyDays || h.days || []);
    }
    if (!h.reminder) {
      h.reminder = {
        enabled: false,
        time: '08:00',
        days: h.frequencyDays?.length
          ? normalizeHabitFrequencyDays(h.frequencyDays).map(key => DAY_KEY_TO_JS_DAY[key]).filter(day => day !== undefined)
          : [0, 1, 2, 3, 4, 5, 6],
        message: ''
      };
    }
  });
  parsed.records.forEach(r => { if (r.mood === undefined) r.mood = 0; });
  if (!parsed.workoutData) parsed.workoutData = getWorkoutData();
  if (!parsed.workoutData.exercises) parsed.workoutData.exercises = WORKOUT_EXERCISES.map(e => ({ ...e, custom: false }));
  if (!parsed.workoutData.routines) parsed.workoutData.routines = SAMPLE_ROUTINES.map(r => ({ id: r.id, name: r.name, muscleGroups: r.mgs, exercises: r.exs, createdAt: toYYYYMMDD(addDays(new Date(), -60)) }));
  if (!parsed.workoutData.sessions) parsed.workoutData.sessions = genSampleSessions();
  if (!parsed.financeData) parsed.financeData = getFinanceData();
  if (!parsed.financeData.currency) parsed.financeData.currency = 'USD';
  if (!parsed.financeData.copRate) parsed.financeData.copRate = 4000;
  if (!parsed.financeData.categories) parsed.financeData.categories = getFinanceData().categories;
  if (!parsed.financeData.transactions) parsed.financeData.transactions = [];
  if (parsed.financeData.monthlyBudget === undefined) parsed.financeData.monthlyBudget = 0;
  if (!parsed.financeData.budgets) parsed.financeData.budgets = {};
  if (!parsed.financeData.accountTags) parsed.financeData.accountTags = getFinanceData().accountTags;
  if (!parsed.financeData.accounts || !parsed.financeData.accounts.length) parsed.financeData.accounts = getFinanceData().accounts;
  parsed.financeData.accounts = parsed.financeData.accounts.map(account => ({
    ...account,
    tagId: account.tagId || (account.type === 'credit'  ? 'credit_card' : account.type === 'bank'  ? 'checking' : account.type || 'custom'),
    currency: account.currency === 'COP'  ? 'COP' : 'USD'
  }));
  const legacyDebtAccounts = parsed.financeData.accounts.filter(account => (
    String(account.id || '').startsWith('debt_')
    || account.type === 'loan'
    || account.tagId === 'loan'
  ));
  const existingDebts = Array.isArray(parsed.financeData.debts) ? parsed.financeData.debts : [];
  const migratedDebts = legacyDebtAccounts.map(account => ({
    id: account.id,
    name: account.name || 'Deuda',
    currency: account.currency === 'COP' ? 'COP' : 'USD',
    total: Math.max(0, Number(account.debtTotal || Math.abs(Number(account.balance || 0)))),
    dueDate: account.debtDueDate || toYYYYMMDD(new Date()),
    minimumPayment: Math.max(0, Number(account.debtMinimumPayment || 0)),
    reminderEnabled: account.debtReminderEnabled !== false,
    reminderDaysBefore: Math.max(0, Number(account.debtReminderDaysBefore || 0)),
    createdAt: account.debtCreatedAt || new Date().toISOString()
  }));
  parsed.financeData.debts = [...existingDebts, ...migratedDebts]
    .filter((debt, index, list) => (
      debt?.id && list.findIndex(item => item?.id === debt.id) === index
    ))
    .map(debt => {
      const rawInstallmentCount = Number(debt.installmentCount);
      const installmentCount = Number.isInteger(rawInstallmentCount) && rawInstallmentCount > 0
        ? Math.min(360, rawInstallmentCount)
        : null;
      return {
        ...debt,
        installmentCount
      };
    });
  parsed.financeData.accounts = parsed.financeData.accounts.filter(account => !legacyDebtAccounts.some(debt => debt.id === account.id));
  parsed.financeData.transactions = parsed.financeData.transactions.map(transaction => {
    const isLegacyDebtPayment = transaction.type === 'income' && (
      String(transaction.id || '').startsWith('debt_pay_')
      || transaction.note === 'Pago registrado desde deudas'
    );
    if (isLegacyDebtPayment) {
      return {
        ...transaction,
        type: 'debt_payment',
        category: 'debt_payment',
        debtId: transaction.debtId || transaction.debtAccountId || transaction.accountId,
        debtAccountId: transaction.debtId || transaction.debtAccountId || transaction.accountId,
        accountId: transaction.sourceAccountId || null
      };
    }
    if (transaction.type === 'debt_payment') {
      return {
        ...transaction,
        category: 'debt_payment',
        debtId: transaction.debtId || transaction.debtAccountId,
        debtAccountId: transaction.debtId || transaction.debtAccountId
      };
    }
    const isLegacyTransferIncome = transaction.type === 'income' && (
      String(transaction.id || '').endsWith('_in')
      || String(transaction.note || '').startsWith('Transferencia desde ')
    );
    return isLegacyTransferIncome ? { ...transaction, category: 'transfer' } : transaction;
  });
  if (!parsed.financeData.recurring) parsed.financeData.recurring = [];
  if (!parsed.financeData.subscriptions) parsed.financeData.subscriptions = [];
  if (!parsed.financeData.goals) parsed.financeData.goals = [];
  parsed.healthData = normalizeHealthData(parsed.healthData || getHealthData());
  if (!parsed.studyData) parsed.studyData = getStudyData();
  if (!parsed.studyData.subjects) parsed.studyData.subjects = [];
  if (!parsed.studyData.sessions) parsed.studyData.sessions = [];
  parsed.studyData.subjects.forEach(s => { if (!s.topics) s.topics = []; if (!s.goalHours) s.goalHours = 0; });
  parsed.readingData = getReadingData();
  if (!parsed.dreamGoals) parsed.dreamGoals = getDreamGoals();
  parsed.dreamGoals = (parsed.dreamGoals || []).map(goal => ({
    ...goal,
    image: typeof goal.image === 'string' && goal.image.startsWith('data:')  ? '' : goal.image
  }));
  if (!parsed.agenda) parsed.agenda = {};
  if (!parsed.agendaNotes) parsed.agendaNotes = {};
  if (!parsed.agendaTodos) parsed.agendaTodos = {};
  if (!parsed.agendaTodoLabels) parsed.agendaTodoLabels = [];
  setGlobalNotificationsEnabled(parsed.user.notificationsEnabled !== false);
  return parsed;
};

// SECTION: Local/cloud persistence, authentication identity and push subscriptions.
const saveLocalData = (data) => {
  localStorage.setItem('habitTrackerData', JSON.stringify(data));
};

const loadData = () => {
  try {
    const raw = localStorage.getItem('habitTrackerData');
    if (raw) {
      const parsed = normalizeLoadedData(JSON.parse(repairMojibakeText(raw)));
      if (parsed) {
        saveLocalData(parsed);
        return parsed;
      }
    }
  } catch (e) {}
  const data = normalizeLoadedData(getDefaultData()) || getDefaultData();
  saveLocalData(data);
  return data;
};

const CLOUD_TABLE = 'habitflow_user_data';
const NOTIFICATION_SENT_STORAGE = 'habitflowNotificationSent';
const GLOBAL_NOTIFICATIONS_STORAGE = 'habitflowNotificationsEnabled';
const CREATOR_EMAIL = 'ventasdeeproots09@gmail.com';
let cloudSaveTimer = null;
let lastCloudSave = Promise.resolve();

const emitCloudSyncStatus = (detail) => {
  try {
    window.dispatchEvent(new CustomEvent('habitflow-cloud-sync', { detail }));
  } catch {}
};

const getClerkUserId = () => window.Clerk?.user?.id || null;

const getClerkIdentity = () => {
  const clerkUser = window.Clerk?.user;
  const primaryEmail = clerkUser?.primaryEmailAddress?.emailAddress
    || clerkUser?.emailAddresses?.find(item => item.id === clerkUser?.primaryEmailAddressId)?.emailAddress
    || clerkUser?.emailAddresses?.[0]?.emailAddress
    || '';
  return {
    id: clerkUser?.id || null,
    email: String(primaryEmail || '').trim().toLowerCase(),
    name: clerkUser?.fullName
      || [clerkUser?.firstName, clerkUser?.lastName].filter(Boolean).join(' ')
      || clerkUser?.username
      || 'Usuario',
    imageUrl: clerkUser?.imageUrl || ''
  };
};

const isLocalCreatorPreview = () => {
  if (!['localhost', '127.0.0.1'].includes(window.location.hostname)) return false;
  const params = new URLSearchParams(window.location.search);
  return params.get('dev-preview') === '1' && params.get('creator-preview') === '1';
};

const hasCreatorAccess = () => getClerkIdentity().email === CREATOR_EMAIL || isLocalCreatorPreview();

const callCreatorNotificationsApi = async (payload) => {
  if (isLocalCreatorPreview()) {
    if (payload?.action === 'list_users') {
      return {
        ok: true,
        creator: { id: 'creator-preview', email: CREATOR_EMAIL, name: 'Daniel Zuluaga' },
        users: [
          { id: 'creator-preview', name: 'Daniel Zuluaga', email: CREATOR_EMAIL, imageUrl: '', devices: 2, notificationsEnabled: true, isCreator: true },
          { id: 'user-preview-1', name: 'Cliente de prueba', email: 'cliente@habitflow.app', imageUrl: '', devices: 1, notificationsEnabled: true, isCreator: false },
          { id: 'user-preview-2', name: 'Usuario sin avisos', email: 'sinavisos@habitflow.app', imageUrl: '', devices: 0, notificationsEnabled: false, isCreator: false }
        ]
      };
    }
    return {
      ok: true,
      preview: true,
      recipients: payload?.audience === 'all' ? 2 : (payload?.userIds || []).length,
      sent: payload?.audience === 'all' ? 3 : (payload?.userIds || []).length,
      failed: 0
    };
  }

  const token = await window.Clerk?.session?.getToken();
  if (!token) throw new Error('Tu sesión de creador no está disponible. Vuelve a iniciar sesión.');
  if (!window.HABITFLOW_SUPABASE_URL || !window.HABITFLOW_SUPABASE_PUBLISHABLE_KEY) {
    throw new Error('La conexión segura con Supabase no está configurada.');
  }

  const response = await fetch(`${window.HABITFLOW_SUPABASE_URL}/functions/v1/habitflow-creator-notifications`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      apikey: window.HABITFLOW_SUPABASE_PUBLISHABLE_KEY,
      Authorization: `Bearer ${token}`
    },
    body: JSON.stringify(payload || {})
  });
  const result = await response.json().catch(() => ({}));
  if (!response.ok || result?.ok === false) {
    if (response.status === 404) {
      throw new Error('El servicio seguro de clientes todavía no está publicado en Supabase.');
    }
    throw new Error(result?.error || 'No se pudo completar la operación de creador.');
  }
  return result;
};

const getCloudClient = () => {
  if (!window.createSupabaseClient || !window.HABITFLOW_SUPABASE_URL || !window.HABITFLOW_SUPABASE_PUBLISHABLE_KEY) return null;
  return window.createSupabaseClient(
    window.HABITFLOW_SUPABASE_URL,
    window.HABITFLOW_SUPABASE_PUBLISHABLE_KEY,
    {
      accessToken: async () => window.Clerk?.session?.getToken() ?? null
    }
  );
};

const loadCloudData = async () => {
  const userId = getClerkUserId();
  const client = getCloudClient();
  if (!userId || !client) return { ok: false, reason: 'Nube no disponible.' };
  try {
    const { data, error } = await client
      .from(CLOUD_TABLE)
      .select('data, updated_at')
      .eq('user_id', userId)
      .maybeSingle();
    if (error) return { ok: false, reason: error.message };
    const normalized = normalizeLoadedData(data?.data);
    return { ok: true, data: normalized, updatedAt: data?.updated_at || null };
  } catch (err) {
    return { ok: false, reason: err.message || 'No se pudo cargar la nube.' };
  }
};

const saveCloudDataNow = async (data) => {
  const userId = getClerkUserId();
  const identity = getClerkIdentity();
  const client = getCloudClient();
  if (!userId || !client || !data) return { ok: false, reason: 'Nube no disponible.' };
  const payload = {
    user_id: userId,
    data: {
      ...data,
      user: {
        ...data.user,
        clerkUserId: userId,
        clerkEmail: identity.email || data.user?.clerkEmail || '',
        clerkName: identity.name || data.user?.clerkName || data.user?.name || 'Usuario',
        clerkImageUrl: identity.imageUrl || data.user?.clerkImageUrl || ''
      }
    },
    updated_at: new Date().toISOString()
  };
  try {
    const { error } = await client
      .from(CLOUD_TABLE)
      .upsert(payload, { onConflict: 'user_id' });
    if (error) return { ok: false, reason: error.message };
    return { ok: true };
  } catch (err) {
    return { ok: false, reason: err.message || 'No se pudo guardar en la nube.' };
  }
};

const queueCloudSave = (data) => {
  if (!getClerkUserId()) {
    emitCloudSyncStatus({ status: 'local', label: 'Guardado local', reason: 'No hay sesión de Clerk activa.' });
    return;
  }
  emitCloudSyncStatus({ status: 'saving', label: 'Guardando nube', reason: 'Sincronizando el Último cambio con Supabase.' });
  clearTimeout(cloudSaveTimer);
  cloudSaveTimer = setTimeout(() => {
    lastCloudSave = lastCloudSave
      .then(() => saveCloudDataNow(data))
      .then(result => {
        emitCloudSyncStatus(result.ok
           ? { status: 'active', label: 'Nube activa', reason: 'Último cambio guardado en Supabase.' }
          : { status: 'local', label: 'Guardado local', reason: result.reason || 'No se pudo guardar en Supabase.' });
      })
      .catch(err => {
        emitCloudSyncStatus({ status: 'local', label: 'Guardado local', reason: err?.message || 'No se pudo guardar en Supabase.' });
      });
  }, 120);
};

const saveData = (data) => {
  saveLocalData(data);
  queueCloudSave(data);
};

const getNotificationPermissionState = () => {
  if (typeof Notification === 'undefined') return 'unsupported';
  return Notification.permission || 'default';
};

const areGlobalNotificationsEnabled = () => {
  try {
    const stored = localStorage.getItem(GLOBAL_NOTIFICATIONS_STORAGE);
    if (stored !== null) return stored !== 'false';
    const data = JSON.parse(localStorage.getItem('habitTrackerData') || '{}');
    return data?.user?.notificationsEnabled !== false;
  } catch {
    return true;
  }
};

const setGlobalNotificationsEnabled = (enabled) => {
  try { localStorage.setItem(GLOBAL_NOTIFICATIONS_STORAGE, enabled ? 'true' : 'false'); } catch {}
};

const getNotificationStatusLabel = (permission = getNotificationPermissionState()) => {
  if (!areGlobalNotificationsEnabled()) return 'Desactivadas';
  if (permission === 'granted') return 'Activas';
  if (permission === 'denied') return 'Bloqueadas';
  if (permission === 'unsupported') return 'No disponibles';
  return 'Sin activar';
};

const urlBase64ToUint8Array = (base64String) => {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; i += 1) outputArray[i] = rawData.charCodeAt(i);
  return outputArray;
};

const savePushSubscription = async (subscription) => {
  const client = getCloudClient();
  const userId = getClerkUserId();
  if (!client || !userId || !subscription?.endpoint) {
    return { ok: false, reason: 'Para recibir avisos con la app cerrada debes iniciar sesión y tener la nube activa.' };
  }
  try {
    const { error } = await client
      .from('habitflow_push_subscriptions')
      .upsert({
        user_id: userId,
        endpoint: subscription.endpoint,
        subscription: subscription.toJSON(),
        user_agent: navigator.userAgent || '',
        enabled: areGlobalNotificationsEnabled(),
        last_seen_at: new Date().toISOString()
      }, { onConflict: 'endpoint' });
    if (error) return { ok: false, reason: error.message };
    return { ok: true };
  } catch (error) {
    return { ok: false, reason: error?.message || 'No se pudo guardar la suscripción push.' };
  }
};

const updatePushSubscriptionsEnabled = async (enabled) => {
  const client = getCloudClient();
  const userId = getClerkUserId();
  if (!client || !userId) return { ok: false, reason: 'La nube no está disponible.' };
  try {
    const { error } = await client
      .from('habitflow_push_subscriptions')
      .update({ enabled: !!enabled, last_seen_at: new Date().toISOString() })
      .eq('user_id', userId);
    return error ? { ok: false, reason: error.message } : { ok: true };
  } catch (error) {
    return { ok: false, reason: error?.message || 'No se pudo actualizar la preferencia global.' };
  }
};

const requestHabitFlowNotifications = async () => {
  if (!areGlobalNotificationsEnabled()) {
    return { ok: false, permission: getNotificationPermissionState(), reason: 'Las notificaciones globales están desactivadas en HabitFlow.' };
  }
  if (typeof Notification === 'undefined') {
    return { ok: false, permission: 'unsupported', reason: 'Este navegador no soporta notificaciones web.' };
  }
  if (!window.isSecureContext && !['localhost', '127.0.0.1'].includes(window.location.hostname)) {
    return { ok: false, permission: Notification.permission, reason: 'Las notificaciones requieren HTTPS.' };
  }
  try {
    let registration = null;
    if ('serviceWorker' in navigator) {
      try { await navigator.serviceWorker.register('./sw.js'); } catch {}
      try { registration = await navigator.serviceWorker.ready; } catch {}
    }
    const permission = Notification.permission === 'default'
       ? await Notification.requestPermission()
      : Notification.permission;
    if (permission === 'granted' && registration && 'PushManager' in window && window.HABITFLOW_VAPID_PUBLIC_KEY) {
      try {
        let subscription = await registration.pushManager.getSubscription();
        if (!subscription) {
          subscription = await registration.pushManager.subscribe({
            userVisibleOnly: true,
            applicationServerKey: urlBase64ToUint8Array(window.HABITFLOW_VAPID_PUBLIC_KEY)
          });
        }
        const saved = await savePushSubscription(subscription);
        return {
          ok: saved.ok,
          permission,
          reason: saved.ok
             ? 'Push real activo. Este dispositivo ya puede recibir avisos aúnque HabitFlow esté cerrado, cuando el servidor de alarmas está activo.'
            : `Permiso activo, pero falta guardar el dispositivo: ${saved.reason}`
        };
      } catch (error) {
        return {
          ok: true,
          permission,
          reason: `Permiso activo para avisos locales, pero el push cerrado no quedó suscrito: ${error?.message || 'revisa el dispositivo.'}`
        };
      }
    }
    return {
      ok: permission === 'granted',
      permission,
      reason: permission === 'granted'
         ? 'Notificaciones activas en este dispositivo. Para que suene en todos, abre HabitFlow en cada PC o celular y activa sus notificaciones una vez.'
        : permission === 'denied'
           ? 'El navegador bloqueó las notificaciones. Actívalas desde permisos del sitio.'
          : 'No se concedió el permiso.'
    };
  } catch {
    return { ok: false, permission: getNotificationPermissionState(), reason: 'No se pudo activar el permiso de notificaciones.' };
  }
};

const showHabitFlowNotification = async (title, options = {}) => {
  if (!areGlobalNotificationsEnabled()) return false;
  if (typeof Notification === 'undefined' || Notification.permission !== 'granted') return false;
  const payload = {
    badge: './icon-192-20260603.png',
    icon: './icon-192-20260603.png',
    silent: false,
    requireInteraction: false,
    ...options
  };
  try {
    if ('serviceWorker' in navigator) {
      const registration = await navigator.serviceWorker.ready;
      if (registration?.showNotification) {
        await registration.showNotification(title, payload);
        return true;
      }
    }
    new Notification(title, payload);
    return true;
  } catch {
    try {
      new Notification(title, payload);
      return true;
    } catch {
      return false;
    }
  }
};

